func TestResponse_MarshalsResult(t *testing.T) {
	t.Parallel()

	r := Response{
		ID:     NewIntID(1),
		Result: json.RawMessage(`{"server":"echo/0.1"}`),
	}
	got, err := json.Marshal(r)
	if err != nil {
